// ═══════════════════════════════════════════════════════════════════
// SMILEY MOUND - Fully animated generative p5.js sketch
// Synthograsizer Workflow Template
// ═══════════════════════════════════════════════════════════════════

const CW = 768;

// Particles: a pool of moving particles that live on the mound
let particles = [];
let bgParticles = [];
let floaters = [];
let blinkTimer = 200;
let isBlinking = false;
let blinkFrame = 0;
let faceDir = 1;
let faceOff = 100;
let eyeWX = 28;
let eyeWY = 80;
let smileW = 120;
let smileH = 110;
let smileSW = 18;
let smileAng = 0.02;
let smileBaseY = 160;
let _prevMoundHue = -1;
let _prevBgHue = -1;
let _prevBgStyle = '';

p.setup = function() {
  p.createCanvas(CW, CW);
  p.colorMode(p.HSB, 360, 100, 100, 100);
  // Seed the face once
  faceDir = p.random() > 0.5 ? 1 : -1;
  faceOff = p.random(50, 150) * faceDir;
  eyeWX = p.random(15, 42);
  eyeWY = p.random(36, 128);
  smileW = Math.abs(faceOff) * p.random(0.95, 1.75);
  smileH = p.random(CW / 7.5, CW / 6.9);
  smileSW = p.random(12, 26);
  smileAng = p.random(-0.05, 0.05);
  smileBaseY = p.random(140, 180);
  // Spawn mound surface particles
  for (let i = 0; i < 200; i++) {
    particles.push(spawnMoundParticle());
  }
  // Spawn floating particles
  for (let i = 0; i < 30; i++) {
    floaters.push({
      x: p.random(CW * 0.15, CW * 0.85),
      y: p.random(CW * 0.2, CW * 0.7),
      vx: p.random(-0.3, 0.3),
      vy: p.random(-0.8, -0.2),
      size: p.random(3, 14),
      alpha: p.random(20, 70),
      hueOff: p.random(-20, 20)
    });
  }
};

function spawnMoundParticle() {
  // Spawn inside mound ellipse
  let angle = p.random(p.TWO_PI);
  let r = p.random(0.1, 1);
  let mx = CW / 2 + Math.cos(angle) * r * CW * 0.45;
  let my = CW * 0.6 + Math.sin(angle) * r * CW * 0.35;
  if (my < CW * 0.35) my = CW * 0.35 + p.random(0, CW * 0.3);
  return {
    x: mx, y: my,
    vx: p.random(-0.5, 0.5), vy: p.random(-0.4, 0.1),
    size: p.random(4, 30),
    hueOff: p.random(-15, 15),
    sat: p.random(40, 80),
    bri: p.random(50, 90),
    alpha: p.random(30, 80),
    life: p.random(60, 300)
  };
}

p.draw = function() {
  let moundHue    = parseFloat(p.getSynthVar('mound_hue'))    || 90;
  let bgHue       = parseFloat(p.getSynthVar('bg_hue'))       || 270;
  let bgDensity   = parseInt(p.getSynthVar('bg_density'))     || 3000;
  let moundDensity= parseInt(p.getSynthVar('mound_density'))  || 3000;
  let bgStyle     = p.getSynthVar('bg_style')                 || 'strokes';
  let t = p.frameCount;

  // Force full clear when hue or style changes so old colors don't linger
  let hueChanged = (moundHue !== _prevMoundHue || bgHue !== _prevBgHue || bgStyle !== _prevBgStyle);
  _prevMoundHue = moundHue;
  _prevBgHue = bgHue;
  _prevBgStyle = bgStyle;

  if (hueChanged) {
    p.background(bgHue, 20, 96);
  }

  // ─── Animated background with semi-transparent overlay for trails ───
  p.noStroke();
  p.fill(bgHue, 20, 96, 12);
  p.rect(0, 0, CW, CW);

  // Periodic full clear to prevent muddiness
  if (t % 120 === 1) {
    p.background(bgHue, 20, 96);
  }

  // ─── Background marks: draw a batch each frame ───
  let marksPerFrame = Math.max(20, Math.floor(bgDensity / 60));
  if (bgStyle === 'strokes') {
    for (let i = 0; i < marksPerFrame; i++) {
      let x = p.random(CW), y = p.random(CW);
      p.stroke(bgHue, p.random(8, 99), p.random(48, 100), p.random(5, 30));
      p.strokeWeight(p.random(1, 6));
      let len = p.random(20, 200);
      let ang = p.noise(x * 0.005, y * 0.005, t * 0.008) * p.TWO_PI * 2;
      p.line(x, y, x + Math.cos(ang) * len, y + Math.sin(ang) * len);
    }
  } else if (bgStyle === 'dots') {
    p.noStroke();
    for (let i = 0; i < marksPerFrame; i++) {
      let x = p.random(CW), y = p.random(CW);
      let sz = p.random(2, 16) * (1 + Math.sin(t * 0.05 + x * 0.01) * 0.3);
      p.fill(bgHue, p.random(10, 80), p.random(60, 100), p.random(8, 40));
      p.ellipse(x, y, sz);
    }
  } else if (bgStyle === 'cross-hatch') {
    for (let i = 0; i < marksPerFrame; i++) {
      let x = p.random(CW), y = p.random(CW);
      let len = p.random(10, 50);
      p.stroke(bgHue, p.random(20, 70), p.random(50, 90), p.random(8, 35));
      p.strokeWeight(1);
      let ang = p.noise(x * 0.01, y * 0.01, t * 0.005) * p.PI;
      p.line(x, y, x + Math.cos(ang) * len, y + Math.sin(ang) * len);
    }
  }

  // ─── Mound body with breathing ───
  let breathe = 1 + Math.sin(t * 0.025) * 0.02;
  p.push();
  p.translate(CW / 2, CW);
  p.scale(breathe, breathe);
  p.translate(-CW / 2, -CW);

  // Mound base
  p.noStroke();
  p.fill(moundHue, 60, 60, 70);
  p.ellipse(CW / 2, CW + CW / 3.5, CW, CW + CW / 1.05);

  // ─── Mound surface particles (move & respawn) ───
  let targetCount = Math.max(50, Math.floor(moundDensity / 15));
  while (particles.length < targetCount) particles.push(spawnMoundParticle());
  while (particles.length > targetCount) particles.pop();

  p.noStroke();
  for (let i = particles.length - 1; i >= 0; i--) {
    let pt = particles[i];
    let nx = p.noise(pt.x * 0.01, pt.y * 0.01, t * 0.01) - 0.5;
    let ny = p.noise(pt.x * 0.01 + 100, pt.y * 0.01, t * 0.01) - 0.5;
    pt.vx += nx * 0.3;
    pt.vy += ny * 0.3 - 0.02;
    pt.vx *= 0.95;
    pt.vy *= 0.95;
    pt.x += pt.vx;
    pt.y += pt.vy;
    pt.life--;
    pt.alpha *= 0.998;
    let hue = (moundHue + pt.hueOff + Math.sin(t * 0.02 + pt.x * 0.01) * 8) % 360;
    if (hue < 0) hue += 360;
    p.fill(hue, pt.sat, pt.bri, pt.alpha);
    p.ellipse(pt.x, pt.y, pt.size * (0.8 + Math.sin(t * 0.04 + pt.y * 0.02) * 0.2));
    if (pt.life <= 0 || pt.alpha < 3 || pt.y < CW * 0.15 || pt.x < 0 || pt.x > CW) {
      particles[i] = spawnMoundParticle();
    }
  }

  // ─── Floating luminous particles rising upward ───
  p.noStroke();
  for (let f of floaters) {
    f.x += f.vx + Math.sin(t * 0.03 + f.y * 0.01) * 0.5;
    f.y += f.vy;
    let a = f.alpha * (0.6 + Math.sin(t * 0.06 + f.x * 0.02) * 0.4);
    let hue = (moundHue + f.hueOff) % 360;
    if (hue < 0) hue += 360;
    p.fill(hue, 40, 95, a * 0.3);
    p.ellipse(f.x, f.y, f.size * 3);
    p.fill(hue, 30, 100, a);
    p.ellipse(f.x, f.y, f.size);
    if (f.y < CW * 0.05 || f.x < 0 || f.x > CW) {
      f.x = p.random(CW * 0.2, CW * 0.8);
      f.y = CW * 0.55 + p.random(0, CW * 0.15);
      f.vy = p.random(-0.8, -0.2);
      f.vx = p.random(-0.3, 0.3);
    }
  }

  // ─── Eyes with blink + look-around ───
  blinkTimer--;
  if (!isBlinking && blinkTimer <= 0) {
    isBlinking = true;
    blinkFrame = 0;
    blinkTimer = 150 + Math.floor(p.random(200));
  }
  if (isBlinking) {
    blinkFrame++;
    if (blinkFrame > 8) isBlinking = false;
  }
  let eyeOpenness = isBlinking ? Math.max(0.04, Math.abs(Math.sin(blinkFrame / 8 * p.PI))) : 1;

  let gazeX = Math.sin(t * 0.013) * 8;
  let gazeY = Math.cos(t * 0.01) * 5;

  let eLX = CW / 2.1 - faceOff + gazeX;
  let eRX = CW / 2.05 + faceOff + gazeX;
  let eLY = CW - CW / 2.5 + gazeY;
  let eRY = CW - CW / 2.5 + gazeY;

  p.fill(0, 0, 3);
  p.noStroke();
  p.ellipse(eLX, eLY, eyeWX, eyeWY * eyeOpenness);
  p.ellipse(eRX, eRY, eyeWX, eyeWY * eyeOpenness);

  if (eyeOpenness > 0.3) {
    p.fill(0, 0, 100, 60);
    p.ellipse(eLX + 3, eLY - eyeWY * 0.15 * eyeOpenness, eyeWX * 0.25, eyeWX * 0.25);
    p.ellipse(eRX + 3, eRY - eyeWY * 0.15 * eyeOpenness, eyeWX * 0.25, eyeWX * 0.25);
  }

  // ─── Smile: gentle sway like the eyes ───
  let smileCX = CW / 2 + faceOff / 2;
  let smileCY = CW - smileBaseY + Math.sin(t * 0.018) * 4;
  let wobble = Math.sin(t * 0.015) * 0.02;
  p.stroke(0, 0, 3);
  p.strokeWeight(smileSW);
  p.noFill();
  p.arc(smileCX, smileCY, smileW, smileH, smileAng + wobble, p.PI);

  p.pop();
};
